const data = JSON.parse(msg.payload);
const classroomId = data.classroom_id || 'sinif-1';
const base = `akilli-sinif/${classroomId}`;
const now = new Date();
const dayMap = ['Paz','Pzt','Sal','Car','Per','Cum','Cmt'];
const todayName = dayMap[now.getDay()];
const today = (data.week || []).find(d => d.day === todayName);
const slots = today ? today.slots : [];

const nowMins = now.getHours()*60 + now.getMinutes();
const toMins = s => parseInt(s.substring(0,2))*60 + parseInt(s.substring(3,5));

let current = null;
for (const s of slots) {
  if (toMins(s.start) <= nowMins && nowMins < toMins(s.end)) { current = s; break; }
}

const teacherName = code => (data.teachers && data.teachers[code]) ? data.teachers[code] : code;
const subjectName = code => (data.subjects && data.subjects[code]) ? data.subjects[code] : code;

const currentMsg = {
  topic: `${base}/schedule/current`,
  payload: JSON.stringify(current ? {
    subject: subjectName(current.code),
    teacher: teacherName(current.teacher),
    start: current.start,
    end: current.end
  } : {}),
  retain: true
};

const todayMsg = {
  topic: `${base}/schedule/today`,
  payload: JSON.stringify(slots.map(s => ({
    code: s.code,
    subject: subjectName(s.code),
    teacher: teacherName(s.teacher),
    start: s.start,
    end: s.end
  }))),
  retain: true
};

const weekMsg = {
  topic: `${base}/schedule/week`,
  payload: JSON.stringify((data.week || []).map(d => ({
    day: d.day,
    slots: d.slots.map(s => ({ code: s.code, teacher: s.teacher }))
  }))),
  retain: true
};

return [[currentMsg, todayMsg, weekMsg]];
